#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max)	((x)>=(min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
	for (cur_arg = 1; cur_arg<argc; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (argc >= cur_arg + 1) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
			verbose = 1;
        }
    }

	if (cols < 0 || rows < 0 || pyramid_height < 0)
	{
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
		exit(0);
	}
	data = new int[rows * cols];
	wall = new int*[rows];
	for (int n = 0; n < rows; n++)
	{
		wall[n] = data + cols * n;
	}
	result = new int[cols];

	int seed = M_SEED;
	srand(seed);

	for (int i = 0; i < rows; i++)
	{
		for (int j = 0; j < cols; j++)
		{
			wall[i][j] = rand() % 10;
		}
	}
}

void fatal(char *s)
{
	fprintf(stderr, "error: %s\n", s);
}

void dynproc_kernel(int iteration,
                    int* gpuWall,
                    int* gpuSrc,
                    int* gpuResults,
                    int cols,
                    int rows,
                    int startStep,
                    int border,
                    int HALO,
                    int BLOCK_SIZE,
                    int bx,
                    int* outputBuffer)
{
    int small_block_cols = BLOCK_SIZE - (iteration*HALO*2);

    int blkX = (small_block_cols*bx) - border;
    int blkXmax = blkX+BLOCK_SIZE-1;

    int* prev = new int[BLOCK_SIZE];
    int* result_local = new int[BLOCK_SIZE];

    int computed = 0;

    #pragma omp parallel num_threads(BLOCK_SIZE)
    {
        int tx = omp_get_thread_num();

        int xidx = blkX+tx;

        int validXmin = (blkX < 0) ? -blkX : 0;
        int validXmax = (blkXmax > cols-1) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

        int W = tx-1;
        int E = tx+1;

        W = (W < validXmin) ? validXmin : W;
        E = (E > validXmax) ? validXmax : E;

        bool isValid = IN_RANGE(tx, validXmin, validXmax);

        if(IN_RANGE(xidx, 0, cols-1))
        {
            prev[tx] = gpuSrc[xidx];
        }
        #pragma omp barrier

        for (int i = 0; i < iteration; i++)
        {
            bool computed_local = false;
            #pragma omp barrier

            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
            {
                computed_local = true;
                int left = prev[W];
                int up = prev[tx];
                int right = prev[E];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);

                int index = cols*(startStep+i)+xidx;
                result_local[tx] = shortest + gpuWall[index];

                if (tx==11 && i==0)
                {
                    int bufIndex = gpuSrc[xidx];
                    outputBuffer[bufIndex] = 1;
                }
            }
            #pragma omp barrier

            if(i==iteration-1)
            {
                break;
            }

            if(computed_local)
            {
                prev[tx] = result_local[tx];
            }
            #pragma omp barrier
        }

        if (IN_RANGE(tx, 0, BLOCK_SIZE-1) && isValid)
        {
            if( IN_RANGE(tx, iteration, BLOCK_SIZE - iteration - 1) || iteration == 0)
            {
                // last iteration result already stored in prev or result_local
                // but we update gpuResults with last result_local
                gpuResults[xidx] = result_local[tx];
            }
            else if(iteration > 0)
            {
                gpuResults[xidx] = result_local[tx];
            }
        }
    }
    delete[] prev;
    delete[] result_local;
}

int main(int argc, char** argv)
{
	init(argc, argv);

	int borderCols = (pyramid_height) * HALO;

	int size = rows * cols;

	int *gpuWall = data + cols; // equivalent to skipping first row in OpenCL kernel
	int *gpuSrc = data;
	int *gpuResults = new int[cols];
	int *outputBuffer = new int[16384];
	for (int i = 0; i < 16384; i++) {
		outputBuffer[i] = 0;
	}

	int src = 1, final_ret = 0;

	int BLOCK_SIZE = cols; // For OpenMP, we can define BLOCK_SIZE as cols
	int numBlocks = 1; // Since original launch is 1D grid with workgroups, here we do in 1 block for simplicity
	// For larger inputs, consider splitting cols into multiple blocks

	for (int t = 0; t < rows - 1; t += pyramid_height)
	{
		int arg0 = MIN(pyramid_height, rows - t - 1);
		int theHalo = HALO;

		// For each block (only one block here), run kernel emulation
		for (int bx = 0; bx < numBlocks; bx++)
		{
			dynproc_kernel(arg0,
			               gpuWall,
			               gpuSrc,
			               gpuResults,
			               cols,
			               rows,
			               t,
			               borderCols,
			               theHalo,
			               BLOCK_SIZE,
			               bx,
			               outputBuffer);
		}

		// Swap gpuSrc and gpuResults pointer for next iteration
		int* temp = gpuSrc;
		gpuSrc = gpuResults;
		gpuResults = temp;
	}

	// Copy final result
	for (int i = 0; i < cols; i++)
	{
		result[i] = gpuSrc[i];
	}

	outputBuffer[16383] = '\0';

#ifdef BENCH_PRINT
	for (int i = 0; i < cols; i++)
		printf("%d ", data[i]);
	printf("\n");
	for (int i = 0; i < cols; i++)
		printf("%d ", result[i]);
	printf("\n");
#endif

	delete[] data;
	delete[] wall;
	delete[] result;
	delete[] gpuResults;
	delete[] outputBuffer;

	return EXIT_SUCCESS;
}
